// ─── 快取 ────────────────────────────────────────────────────────────────────
const twseCache = { data: BUILTIN_NAMES, ts: Date.now() };  // 預載內建名稱
const nameCache = {};                       // 個股名稱，process 記憶體快取

// ─── 工具 ─────────────────────────────────────────────────────────────────────
function cleanYahooName(raw) {
  return String(raw || "")
    .replace(/股份有限公司/g, "")
    .replace(/有限公司/g, "")
    .replace(/\s+/g, "")
    .trim();
}

// ─── Yahoo K線（核心，前端主要使用） ─────────────────────────────────────────
app.get("/api/yahoo/chart/:symbol", async (req, res) => {
  try {
    const raw = String(req.params.symbol).trim().toUpperCase();

    const fetchYahoo = async (symbol) => {
      const response = await axios.get(
        `https://query1.finance.yahoo.com/v8/finance/chart/${symbol}`,
        {
          params: {
            range: req.query.range || "6mo",
            interval: req.query.interval || "1d",
          },
          headers: { "User-Agent": "Mozilla/5.0" },
          timeout: 10000,
        }
      );
      const result = response.data?.chart?.result?.[0];
      if (!result) throw new Error(`No data for ${symbol}`);
      return response.data;
    };

    // 已帶後綴（2330.TW / AAPL）
    if (raw.includes(".")) return res.json(await fetchYahoo(raw));

    // 自動試上市 → 上櫃 → 美股
    const candidates = [`${raw}.TW`, `${raw}.TWO`, raw];
    let lastError = null;
    for (const sym of candidates) {
      try {
        return res.json(await fetchYahoo(sym));
      } catch (err) {
        lastError = err;
      }
    }
    throw lastError;
  } catch (err) {
    console.error("chart error:", err.message);
    res.status(500).json({ error: "Yahoo chart API failed" });
  }
});

// ─── Yahoo 搜尋（輸入代號或中文名，回傳代號 + 中文名 + 產業） ───────────────
// 前端搜尋欄使用，解決名稱要靠靜態表的問題
app.get("/api/yahoo/search", async (req, res) => {
  try {
    const q = String(req.query.q || "").trim();
    if (!q) return res.json({ results: [] });

    // 先查 TWSE 快取（上市上櫃全名單，最準）
    const twseMap = twseCache.data || {};
    const twseMatches = [];
    const qLower = q.toLowerCase();

    for (const [code, entry] of Object.entries(twseMap)) {
      const name = typeof entry === "object" ? entry.name : entry;
      const industry = typeof entry === "object" ? entry.industry : "";
      if (
        code.startsWith(q.toUpperCase()) ||
        name.includes(q)
      ) {
        twseMatches.push({
          symbol: code,
          name,
          industry,
          market: "TW",
          source: "twse",
        });
        if (twseMatches.length >= 8) break;
      }
    }

    if (twseMatches.length > 0) {
      return res.json({ results: twseMatches });
    }

    // 沒有的話去問 Yahoo search API
    const yahooUrl = `https://query1.finance.yahoo.com/v1/finance/search?q=${encodeURIComponent(q)}&quotesCount=8&newsCount=0&lang=zh-Hant-TW&region=TW`;
    const r = await axios.get(yahooUrl, {
      headers: { "User-Agent": "Mozilla/5.0" },
      timeout: 6000,
    });

    const quotes = r.data?.quotes || [];
    const results = quotes
      .filter((item) => item.quoteType === "EQUITY" || item.quoteType === "ETF")
      .map((item) => {
        const rawName = item.shortname || item.longname || item.displayName || item.symbol;
        return {
          symbol: String(item.symbol || "").replace(/\.(TW|TWO)$/i, ""),
          yahooSymbol: item.symbol,
          name: cleanYahooName(rawName),
          market: item.exchange === "TWO" ? "TWO" : item.exchange?.includes("TAI") ? "TW" : "US",
          source: "yahoo",
        };
      })
      .slice(0, 8);

    res.json({ results });
  } catch (err) {
    console.error("search error:", err.message);
    res.json({ results: [] });
  }
});

// ─── 取名稱對照表（直接回傳內建資料，不呼叫外部 API）────────────────────────
async function ensureTwseCache() {
  return BUILTIN_NAMES;
}

// ─── 單一股票名稱查詢（優先查 TWSE，再查 Yahoo）────────────────────────────
app.get("/api/yahoo/name/:symbol", async (req, res) => {
  try {
    const raw = String(req.params.symbol).trim().toUpperCase().replace(/\.(TW|TWO)$/i, "");

    // 1. 先查記憶體快取
    if (nameCache[raw]) return res.json({ symbol: raw, name: nameCache[raw] });

    // 2. 查 TWSE / TPEx 清單（最準確的中文名來源）
    const twseMap = await ensureTwseCache();
    if (twseMap[raw]) {
      const entry = twseMap[raw];
      const name = typeof entry === "object" ? entry.name : entry;
      const industry = typeof entry === "object" ? entry.industry : "";
      nameCache[raw] = name;
      return res.json({ symbol: raw, name, industry });
    }

    // 3. TWSE 查不到（美股 / 新掛牌）才用 Yahoo chart meta
    const candidates = [`${raw}.TW`, `${raw}.TWO`, raw];
    let name = "";

    for (const sym of candidates) {
      try {
        const r = await axios.get(
          `https://query1.finance.yahoo.com/v8/finance/chart/${sym}?range=1d&interval=1d`,
          { headers: { "User-Agent": "Mozilla/5.0" }, timeout: 6000 }
        );
        const meta = r.data?.chart?.result?.[0]?.meta || {};
        const candidate = cleanYahooName(meta.shortName || meta.longName || "");
        if (/[\u4e00-\u9fff]/.test(candidate)) {
          name = candidate;
          break;
        } else if (candidate && !name) {
          name = candidate;
        }
      } catch {}
    }

    if (name) nameCache[raw] = name;
    res.json({ symbol: raw, name: name || raw });
  } catch (err) {
    console.error("name error:", err.message);
    res.json({ symbol: req.params.symbol, name: req.params.symbol });
  }
});

// ─── TWSE + TPEx 全台股名稱清單（前端啟動時抓一次，快取6小時） ───────────────
app.get("/api/twse/list", async (req, res) => {
  // 直接回傳內建名稱對照表，不需要呼叫外部 API
  res.json(BUILTIN_NAMES);
});

// ─── 股票新聞（Google News RSS，中文優先，含日期範圍）──────────────────────────
// 用法：/api/news/2330 或 /api/news/NVDA
// 參數：?name=台積電（可選，提升搜尋精準度）
const newsCache = {};
const NEWS_CACHE_TTL = 15 * 60 * 1000;  // 15 分鐘快取

function getDateWindow(days = 14) {  // 兩週內
  const until = new Date();
  const since = new Date(Date.now() - days * 24 * 60 * 60 * 1000);
  const fmt = (d) => d.toISOString().slice(0, 10);
  return { since: fmt(since), until: fmt(until) };
}

function parseGoogleNewsRSS(xml) {
  const items = xml.match(/<item>([\s\S]*?)<\/item>/g) || [];
  return items.map((item) => {
    const title = (item.match(/<title><!\[CDATA\[([\s\S]*?)\]\]><\/title>/) ||
                   item.match(/<title>([\s\S]*?)<\/title>/))?.[1] || "";
    const link  = (item.match(/<link>([\s\S]*?)<\/link>/))?.[1] ||
                  (item.match(/<guid[^>]*>([\s\S]*?)<\/guid>/))?.[1] || "";
    const pubDate = (item.match(/<pubDate>([\s\S]*?)<\/pubDate>/))?.[1] || "";
    const source  = (item.match(/<source[^>]*>([\s\S]*?)<\/source>/))?.[1] || "";
    const snippet = (item.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/) ||
                     item.match(/<description>([\s\S]*?)<\/description>/))?.[1] || "";

    const cleanSnippet = snippet.replace(/<[^>]+>/g, "").replace(/&nbsp;/g, " ").replace(/&amp;/g, "&").trim();
    const cleanTitle = title.replace(/&amp;/g, "&").replace(/&lt;/g, "<").replace(/&gt;/g, ">").trim();

    return {
      title: cleanTitle,
      snippet: cleanSnippet,
      url: link.trim(),
      publisher: source.trim(),
      publishedAt: pubDate ? new Date(pubDate).toISOString() : null,
      providerPublishTime: pubDate ? Math.floor(new Date(pubDate).getTime() / 1000) : 0,
    };
  }).filter(a => a.title && a.url);
}

app.get("/api/news/:symbol", async (req, res) => {
  try {
    const raw = String(req.params.symbol).trim().toUpperCase().replace(/\.(TW|TWO)$/i, "");
    const nameParam = String(req.query.name || "").trim();

    // 從內建名稱表取中文名
    const stockEntry = BUILTIN_NAMES[raw];
    const stockName = nameParam ||
      (typeof stockEntry === "object" ? stockEntry.name : stockEntry) || raw;

    // 快取
    const cacheKey = raw;
    const cached = newsCache[cacheKey];
    if (cached && Date.now() - cached.ts < NEWS_CACHE_TTL) {
      return res.json(cached.data);
    }

    const { since, until } = getDateWindow(14);
    const isTW = /^\d{4,6}[A-Z]?$/.test(raw);
    let articles = [];

    // ── 台股：用代號 + 中文名搜尋（中文優先）────────────────────────────
    if (isTW) {
      const queries = [
        `${raw} ${stockName} 股票 新聞 最新 after:${since} before:${until}`,
        `${stockName} 股票 after:${since} before:${until}`,
      ];

      for (const q of queries) {
        if (articles.length >= 6) break;
        try {
          const url = `https://news.google.com/rss/search?q=${encodeURIComponent(q)}&hl=zh-TW&gl=TW&ceid=TW:zh-Hant`;
          const r = await axios.get(url, {
            headers: { "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36" },
            timeout: 8000,
            responseType: "text",
          });
          const parsed = parseGoogleNewsRSS(r.data || "");
          articles.push(...parsed);
        } catch {}
      }
    } else {
      // ── 美股：英文搜尋為主 ──────────────────────────────────────────────
      const usName = stockName !== raw ? stockName : raw;
      const queries = [
        `${raw} ${usName} stock news after:${since} before:${until}`,
        `${raw} stock news`,
      ];
      for (const q of queries) {
        if (articles.length >= 6) break;
        try {
          const url = `https://news.google.com/rss/search?q=${encodeURIComponent(q)}&hl=en-US&gl=US&ceid=US:en`;
          const r = await axios.get(url, {
            headers: { "User-Agent": "Mozilla/5.0" },
            timeout: 8000,
            responseType: "text",
          });
          const parsed = parseGoogleNewsRSS(r.data || "");
          articles.push(...parsed);
        } catch {}
      }
    }

    // 去重（依 title 去重）
    const seen = new Set();
    articles = articles.filter(a => {
      if (seen.has(a.title)) return false;
      seen.add(a.title);
      return true;
    }).slice(0, 10);

    const result = {
      symbol: raw,
      name: stockName,
      articles,
      dateWindow: { since, until },
      updatedAt: Date.now(),
    };

    newsCache[cacheKey] = { data: result, ts: Date.now() };
    res.json(result);
  } catch (err) {
    console.error("news error:", err.message);
    res.json({ symbol: req.params.symbol, articles: [], updatedAt: Date.now() });
  }
});

